export const ErrorCode = {
  ParseError: -32700,
  InvalidRequest: -32600,
  MethodNotFound: -32601,
  InvalidParams: -32602,
  InternalError: -32603,
}

export class McpError extends Error {
  constructor(code, message, data) {
    super(message)
    this.code = code
    this.data = data
  }
}

function passthroughSchema() {
  return {
    parse(value) {
      return value
    },
    safeParse(value) {
      return { success: true, data: value }
    },
  }
}

export const CallToolResultSchema = passthroughSchema()
export const CallToolRequestSchema = passthroughSchema()
export const ElicitRequestSchema = passthroughSchema()
export const ElicitationCompleteNotificationSchema = passthroughSchema()
export const JSONRPCMessageSchema = passthroughSchema()
