export const ListRootsRequestSchema = passthroughSchema()
export const ListToolsRequestSchema = passthroughSchema()
export const ListToolsResultSchema = passthroughSchema()
export const PromptListChangedNotificationSchema = passthroughSchema()
export const ReadResourceResultSchema = passthroughSchema()
